import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import "./NewReservation.css";

function NewReservation() {
  const [formData, setFormData] = useState({
    movie: "",
    cinema: "",
    date: "",
    time: "",
    seats: "",
    name: "",
    email: "",
    phone: ""
  });

  const [step, setStep] = useState(1);
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);

  const timeSlots = [
    "10:00 AM", "1:00 PM", "4:00 PM", "7:00 PM", "10:00 PM"
  ];

  // Fetch cinemas from your backend API
  useEffect(() => {
    const fetchCinemas = async () => {
      try {
        // Replace with your actual API endpoint
        const response = await fetch('http://localhost:5000/api/cinemas');
        const data = await response.json();
        if (data.success) {
          setCinemas(data.data);
        }
      } catch (error) {
        console.error('Error fetching cinemas:', error);
        // Fallback mock data for demonstration
        setCinemas([
          {
            _id: "1",
            cinema_name: "Cineplex Downtown",
            cinema_location: "123 Main Street, Downtown",
            ongoing_movies: {
              movie_1: "The Dark Knight",
              movie_2: "Inception",
              movie_3: "Interstellar",
              movie_4: "The Matrix"
            },
            upcoming_movie: "Avatar 2",
            is_active: true
          },
          {
            _id: "2",
            cinema_name: "Mega Cinema",
            cinema_location: "456 Oak Avenue, Uptown",
            ongoing_movies: {
              movie_1: "Titanic",
              movie_2: "Avatar",
              movie_3: "Avengers",
              movie_4: "Spider-Man"
            },
            upcoming_movie: "Black Panther 2",
            is_active: true
          }
        ]);
      } finally {
        setLoading(false);
      }
    };

    fetchCinemas();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleNext = () => {
    if (step < 3) {
      setStep(step + 1);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    alert("Reservation submitted successfully!");
    console.log("Reservation Data:", formData);
  };

  // Get available movies based on selected cinema
  const getAvailableMovies = () => {
    const selectedCinema = cinemas.find(cinema => cinema._id === formData.cinema);
    if (selectedCinema) {
      return [
        selectedCinema.ongoing_movies.movie_1,
        selectedCinema.ongoing_movies.movie_2,
        selectedCinema.ongoing_movies.movie_3,
        selectedCinema.ongoing_movies.movie_4,
        selectedCinema.upcoming_movie
      ].filter(movie => movie);
    }
    return [];
  };

  const renderStep1 = () => (
    <div className="step-content">
      <h3>Select Cinema & Movie</h3>
      
      <div className="form-group">
        <label>Cinema *</label>
        {loading ? (
          <div className="loading">Loading cinemas...</div>
        ) : (
          <select 
            name="cinema" 
            value={formData.cinema} 
            onChange={handleInputChange}
            required
          >
            <option value="">Choose a cinema</option>
            {cinemas.filter(cinema => cinema.is_active).map(cinema => (
              <option key={cinema._id} value={cinema._id}>
                {cinema.cinema_name} - {cinema.cinema_location}
              </option>
            ))}
          </select>
        )}
      </div>
      
      <div className="form-group">
        <label>Movie *</label>
        <select 
          name="movie" 
          value={formData.movie} 
          onChange={handleInputChange}
          required
          disabled={!formData.cinema}
        >
          <option value="">Choose a movie</option>
          {getAvailableMovies().map(movie => (
            <option key={movie} value={movie}>{movie}</option>
          ))}
        </select>
        {!formData.cinema && (
          <p className="help-text">Please select a cinema first</p>
        )}
      </div>
    </div>
  );

  const renderStep2 = () => (
    <div className="step-content">
      <h3>Select Date & Time</h3>
      <div className="form-group">
        <label>Date *</label>
        <input
          type="date"
          name="date"
          value={formData.date}
          onChange={handleInputChange}
          min={new Date().toISOString().split('T')[0]}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Time *</label>
        <select 
          name="time" 
          value={formData.time} 
          onChange={handleInputChange}
          required
        >
          <option value="">Choose a time</option>
          {timeSlots.map(time => (
            <option key={time} value={time}>{time}</option>
          ))}
        </select>
      </div>
      
      <div className="form-group">
        <label>Number of Seats *</label>
        <select 
          name="seats" 
          value={formData.seats} 
          onChange={handleInputChange}
          required
        >
          <option value="">Select seats</option>
          {[1,2,3,4,5,6,7,8].map(num => (
            <option key={num} value={num}>{num} seat{num > 1 ? 's' : ''}</option>
          ))}
        </select>
      </div>
    </div>
  );

  const renderStep3 = () => (
    <div className="step-content">
      <h3>Personal Information</h3>
      <div className="form-group">
        <label>Full Name *</label>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleInputChange}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Email *</label>
        <input
          type="email"
          name="email"
          value={formData.email}
          onChange={handleInputChange}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Phone Number *</label>
        <input
          type="tel"
          name="phone"
          value={formData.phone}
          onChange={handleInputChange}
          required
        />
      </div>
    </div>
  );

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>New Reservation</h1>
          <p>Book your cinema tickets quickly and easily</p>
        </div>
      </section>

      {/* Reservation Form */}
      <section className="reservation-section">
        <div className="container">
          <div className="reservation-form">
            <div className="form-header">
              <h2>Make a Reservation</h2>
              <div className="step-indicator">
                <div className={`step ${step >= 1 ? 'active' : ''}`}>1</div>
                <div className={`step ${step >= 2 ? 'active' : ''}`}>2</div>
                <div className={`step ${step >= 3 ? 'active' : ''}`}>3</div>
              </div>
            </div>

            <form onSubmit={handleSubmit}>
              {step === 1 && renderStep1()}
              {step === 2 && renderStep2()}
              {step === 3 && renderStep3()}

              <div className="form-actions">
                {step > 1 && (
                  <button type="button" onClick={handlePrev} className="btn-secondary">
                    Previous
                  </button>
                )}
                {step < 3 ? (
                  <button type="button" onClick={handleNext} className="btn-primary">
                    Next
                  </button>
                ) : (
                  <button type="submit" className="btn-primary">
                    Complete Reservation
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h3>D&S Creations</h3>
            <p>Your premier destination for cinema advertising and entertainment.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><a href="/mainhome">Home</a></li>
              <li><a href="/new-reservation">New Reservation</a></li>
              <li><a href="/my-reservations">My Reservations</a></li>
              <li><a href="/conus">Contact Us</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Contact Info</h4>
            <p>Email: info@dscreations.com</p>
            <p>Phone: +1 (555) 123-4567</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} D&S Creations. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default NewReservation;
